// ANSI color helpers
const colors = {
  green: (msg) => `\x1b[32m${msg}\x1b[0m`,
  red: (msg) => `\x1b[31m${msg}\x1b[0m`,
  yellow: (msg) => `\x1b[33m${msg}\x1b[0m`,
  blue: (msg) => `\x1b[34m${msg}\x1b[0m`,
  bold: (msg) => `\x1b[1m${msg}\x1b[0m`,
};

function log(stage, message) {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] ${colors.blue(`[${stage}]`)} ${message}`);
}

function logError(stage, message) {
  const timestamp = new Date().toISOString();
  console.error(`[${timestamp}] ${colors.red(`[${stage} ERROR]`)} ${message}`);
}

function logSuccess(stage, message) {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] ${colors.green(`[${stage} ✓]`)} ${message}`);
}

function execCommand(command, options = {}) {
  const defaults = {
    stdio: 'pipe',
    encoding: 'utf-8',
    timeout: CONFIG.testTimeout,
    env: { ...process.env },
  };
  const opts = { ...defaults, ...options };

  try {
    const result = execSync(command, opts);
    return { success: true, output: result ? result.toString().trim() : '' };
  } catch (error) {
    return {
      success: false,
      output: error.stdout ? error.stdout.toString().trim() : '',
      error: error.stderr ? error.stderr.toString().trim() : error.message,
      exitCode: error.status,
    };
  }
}

function ensureDirectory(dirPath) {
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true, mode: 0o755 });
  }
}

function computeFileHash(filePath, algorithm = 'sha256') {
  const fileBuffer = fs.readFileSync(filePath);
  const hash = crypto.createHash(algorithm);
  hash.update(fileBuffer);
  return hash.digest('hex');
}

function computeDirectoryHash(dirPath, algorithm = 'sha256') {
  const hash = crypto.createHash(algorithm);
  const entries = [];

  function walkDir(dir) {
    if (!fs.existsSync(dir)) return;
    const items = fs.readdirSync(dir, { withFileTypes: true }).sort((a, b) =>
      a.name.localeCompare(b.name)
    );
    for (const item of items) {
      const fullPath = path.join(dir, item.name);
      if (item.isDirectory()) {
        if (item.name !== 'node_modules' && item.name !== '.git') {
          walkDir(fullPath);
        }
      } else if (item.isFile()) {
        entries.push(fullPath);
      }
    }
  }

  walkDir(dirPath);
  for (const entry of entries) {
    const relativePath = path.relative(dirPath, entry);
    const fileHash = computeFileHash(entry, algorithm);
    hash.update(`${relativePath}:${fileHash}\n`);
  }

  return hash.digest('hex');
}

