async function stagePreflightChecks() {
  const stage = 'PREFLIGHT';
  log(stage, 'Running preflight checks...');

  // Verify Node.js version
  const nodeVersion = process.version;
  const majorVersion = parseInt(nodeVersion.slice(1).split('.')[0], 10);
  if (majorVersion < 18) {
    throw new Error(`Node.js >= 18 required. Current: ${nodeVersion}`);
  }
  log(stage, `Node.js version: ${nodeVersion}`);

  // Verify npm is available
  const npmResult = execCommand('npm --version');
  if (!npmResult.success) {
    throw new Error('npm is not available');
  }
  log(stage, `npm version: ${npmResult.output}`);

  // Verify package.json exists
  const packageJsonPath = path.resolve(__dirname, 'package.json');
  if (!fs.existsSync(packageJsonPath)) {
    throw new Error('package.json not found');
  }

  // Verify package-lock.json exists for reproducible builds
  const lockfilePath = path.resolve(__dirname, 'package-lock.json');
  if (!fs.existsSync(lockfilePath)) {
    log(stage, colors.yellow('WARNING: package-lock.json not found. Generating one for reproducible builds.'));
    const lockResult = execCommand('npm i --package-lock-only');
    if (!lockResult.success) {
      throw new Error('Failed to generate package-lock.json');
    }
  }

  // Verify lockfile integrity
  const lockfileIntegrityResult = execCommand('npm audit signatures 2>/dev/null || true');
  log(stage, 'Lockfile present for reproducible installs');

  // Check for required environment variables in production
  if (CONFIG.deployTarget === 'production') {
    const requiredEnvVars = ['DEPLOY_TOKEN'];
    const missing = requiredEnvVars.filter((v) => !process.env[v]);
    if (missing.length > 0) {
      log(stage, colors.yellow(`WARNING: Missing env vars for production deploy: ${missing.join(', ')}`));
      log(stage, colors.yellow('Deploy stage will be skipped if credentials are missing.'));
    }
  }

  ensureDirectory(CONFIG.sbomDir);
  ensureDirectory(CONFIG.artifactDir);

  logSuccess(stage, 'Preflight checks passed');
}

