async function stageSecurityAudit() {
  const stage = 'SECURITY';
  log(stage, 'Running security audit...');

  // Run npm audit
  const auditResult = execCommand('npm audit --json 2>/dev/null || true');
  let auditData = {};

  try {
    if (auditResult.output) {
      auditData = JSON.parse(auditResult.output);
    }
  } catch {
    log(stage, colors.yellow('Could not parse audit JSON output'));
  }

  if (auditData.metadata) {
    const vulns = auditData.metadata.vulnerabilities || {};
    const critical = vulns.critical || 0;
    const high = vulns.high || 0;
    const moderate = vulns.moderate || 0;

    log(stage, `Vulnerabilities - Critical: ${critical}, High: ${high}, Moderate: ${moderate}`);

    if (critical > 0) {
      throw new Error(`${critical} critical vulnerabilities found. Fix before deploying.`);
    }

    if (high > 0 && CONFIG.deployTarget === 'production') {
      log(stage, colors.yellow(`WARNING: ${high} high severity vulnerabilities detected`));
    }
  }

  // Save audit report as artifact
  const auditReportPath = path.join(CONFIG.artifactDir, 'audit-report.json');
  fs.writeFileSync(auditReportPath, JSON.stringify(auditData, null, 2), { mode: 0o644 });

  logSuccess(stage, 'Security audit completed');
}

async function stageGenerateSBOM() {
  const stage = 'SBOM';
  log(stage, 'Generating Software Bill of Materials (SBOM)...');

  const packageJsonPath = path.resolve(__dirname, 'package.json');
  const packageLockPath = path.resolve(__dirname, 'package-lock.json');
  const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));

  // Generate CycloneDX-compatible SBOM
  const sbom = {
    bomFormat: 'CycloneDX',
    specVersion: '1.5',
    serialNumber: `urn:uuid:${crypto.randomUUID()}`,
    version: 1,
    metadata: {
      timestamp: new Date().toISOString(),
      tools: [
        {
          vendor: 'ci-cd-pipeline',
          name: 'node-sbom-generator',
          version: '1.0.0',
        },
      ],
      component: {
        type: 'application',
        name: packageJson.name || 'unknown',
        version: packageJson.version || '0.0.0',
        description: packageJson.description || '',
        purl: `pkg:npm/${packageJson.name}@${packageJson.version}`,
      },
    },
    components: [],
    dependencies: [],
  };

  // Parse lockfile for complete dependency tree
  let lockfileData = {};
  if (fs.existsSync(packageLockPath)) {
    try {
      lockfileData = JSON.parse(fs.readFileSync(packageLockPath, 'utf-8'));
    } catch {
      log(stage, colors.yellow('Could not parse package-lock.json'));
    }
  }

  // Extract components from lockfile packages (npm v7+ format)
  const packages = lockfileData.packages || {};
  const componentMap = new Map();

  for (const [pkgPath, pkgInfo] of Object.entries(packages)) {
    if (!pkgPath || pkgPath === '') continue; // Skip root

    const pkgName = pkgPath.replace(/^node_modules\//, '').replace(/.*node_modules\//, '');
    if (!pkgName) continue;

    const component = {
      type: 'library',
      name: pkgName,
      version: pkgInfo.version || 'unknown',
      purl: `pkg:npm/${encodeURIComponent(pkgName)}@${pkgInfo.version}`,
      scope: pkgInfo.dev ? 'optional' : 'required',
      hashes: [],
    };

    // Include integrity hash from lockfile
    if (pkgInfo.integrity) {
      const [algo, hash] = pkgInfo.integrity.split('-', 2);
      if (algo && hash) {
        component.hashes.push({
          alg: algo.toUpperCase().replace('SHA', 'SHA-'),
          content: Buffer.from(hash, 'base64').toString('hex'),
        });
      }
    }

    // Include resolved URL for provenance
    if (pkgInfo.resolved) {
      component.externalReferences = [
        {
          type: 'distribution',
          url: pkgInfo.resolved,
        },
      ];
    }

    componentMap.set(pkgName, component);
    sbom.components.push(component);
  }

  // Build dependency graph
  const rootDeps = {
    ref: `pkg:npm/${packageJson.name}@${packageJson.version}`,
    dependsOn: [],
  };

  const allDeps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  for (const depName of Object.keys(allDeps)) {
    const comp = componentMap.get(depName);
    if (comp) {
      rootDeps.dependsOn.push(comp.purl);
    }
  }
  sbom.dependencies.push(rootDeps);

  // Write SBOM files
  const sbomJsonPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json');
  fs.writeFileSync(sbomJsonPath, JSON.stringify(sbom, null, 2), { mode: 0o644 });

  // Generate SBOM hash for integrity verification
  const sbomHash = computeFileHash(sbomJsonPath);
  const sbomHashPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json.sha256');
  fs.writeFileSync(sbomHashPath, `${sbomHash}  sbom.cdx.json\n`, { mode: 0o644 });

  // Also try to generate SBOM using npm sbom if available (npm 9.5+)
  const npmSbomResult = execCommand('npm sbom --sbom-format cyclonedx 2>/dev/null || true');
  if (npmSbomResult.success && npmSbomResult.output && npmSbomResult.output.startsWith('{')) {
    const npmSbomPath = path.join(CONFIG.sbomDir, 'sbom.npm.cdx.json');
    fs.writeFileSync(npmSbomPath, npmSbomResult.output, { mode: 0o644 });
    log(stage, 'Also generated SBOM via npm sbom command');
  }

  // Copy SBOM to artifacts
  const artifactSbomPath = path.join(CONFIG.artifactDir, 'sbom.cdx.json');
  fs.copyFileSync(sbomJsonPath, artifactSbomPath);

  log(stage, `SBOM contains ${sbom.components.length} components`);
  log(stage, `SBOM hash (SHA-256): ${sbomHash}`);

  logSuccess(stage, `SBOM generated at ${sbomJsonPath}`);

  return sbom;
}

function validateSBOM(sbom) {
  const stage = 'SBOM-VALIDATE';
  log(stage, 'Validating SBOM completeness and integrity...');

  const errors = [];

  // Validate required SBOM fields
  if (!sbom.bomFormat || sbom.bomFormat !== 'CycloneDX') {
    errors.push('Missing or invalid bomFormat');
  }
  if (!sbom.specVersion) {
    errors.push('Missing specVersion');
  }
  if (!sbom.serialNumber) {
    errors.push('Missing serialNumber');
  }
  if (!sbom.metadata || !sbom.metadata.timestamp) {
    errors.push('Missing metadata timestamp');
  }
  if (!sbom.metadata || !sbom.metadata.component) {
    errors.push('Missing metadata component (root application)');
  }
  if (!sbom.components || !Array.isArray(sbom.components)) {
    errors.push('Missing or invalid components array');
  }

  // Validate each component has required fields
  if (sbom.components) {
    for (const comp of sbom.components) {
      if (!comp.name) {
        errors.push(`Component missing name: ${JSON.stringify(comp)}`);
      }
      if (!comp.version) {
        errors.push(`Component ${comp.name} missing version`);
      }
      if (!comp.purl) {
        errors.push(`Component ${comp.name}@${comp.version} missing purl`);
      }
    }
  }

  // Verify SBOM file integrity
  const sbomJsonPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json');
  const sbomHashPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json.sha256');

  if (fs.existsSync(sbomJsonPath) && fs.existsSync(sbomHashPath)) {
    const currentHash = computeFileHash(sbomJsonPath);
    const storedHashLine = fs.readFileSync(sbomHashPath, 'utf-8').trim();
    const storedHash = storedHashLine.split(/\s+/)[0];

    if (currentHash !== storedHash) {
      errors.push('SBOM file integrity check failed - hash mismatch');
    } else {
      log(stage, 'SBOM file integrity verified');
    }
  } else {
    errors.push('SBOM file or hash file missing');
  }

  // Cross-reference with installed node_modules
  const nodeModulesPath = path.resolve(__dirname, 'node_modules');
  if (fs.existsSync(nodeModulesPath) && sbom.components) {
    const packageJsonPath = path.resolve(__dirname, 'package.json');
    const packageJson = JSON.parse(fs.readFileSync(packageJsonPath, 'utf-8'));
    const declaredDeps = Object.keys({
      ...packageJson.dependencies,
      ...packageJson.devDependencies,
    });

    const sbomComponentNames = new Set(sbom.components.map((c) => c.name));

    for (const dep of declaredDeps) {
      if (!sbomComponentNames.has(dep)) {
        errors.push(`Declared dependency "${dep}" missing from SBOM`);
      }
    }
  }

  if (errors.length > 0) {
    for (const err of errors) {
      logError(stage, err);
    }
    throw new Error(`SBOM validation failed with ${errors.length} error(s)`);
  }

  logSuccess(stage, 'SBOM validation passed');
}

