async function stageBuild() {
  const stage = 'BUILD';
  log(stage, 'Building application...');

  const packageJson = JSON.parse(fs.readFileSync(path.resolve(__dirname, 'package.json'), 'utf-8'));

  if (packageJson.scripts && packageJson.scripts.build) {
    // Clean previous build
    if (fs.existsSync(CONFIG.buildDir)) {
      fs.rmSync(CONFIG.buildDir, { recursive: true, force: true });
    }

    const buildResult = execCommand('npm run build', {
      timeout: 600000,
      env: {
        ...process.env,
        NODE_ENV: CONFIG.nodeEnv,
      },
    });

    if (!buildResult.success) {
      throw new Error(`Build failed:\n${buildResult.error || buildResult.output}`);
    }

    // Verify build output exists
    if (!fs.existsSync(CONFIG.buildDir)) {
      log(stage, colors.yellow('Build directory not found at expected path, checking for alternative outputs...'));
    }

    // Generate build artifact hash for integrity
    if (fs.existsSync(CONFIG.buildDir)) {
      const buildHash = computeDirectoryHash(CONFIG.buildDir);
      const buildManifest = {
        timestamp: new Date().toISOString(),
        buildHash,
        nodeVersion: process.version,
        environment: CONFIG.nodeEnv,
        appVersion: packageJson.version,
        appName: packageJson.name,
      };

      const manifestPath = path.join(CONFIG.artifactDir, 'build-manifest.json');
      fs.writeFileSync(manifestPath, JSON.stringify(buildManifest, null, 2), { mode: 0o644 });
      log(stage, `Build hash (SHA-256): ${buildHash}`);
    }

    logSuccess(stage, 'Build completed successfully');
  } else {
    log(stage, colors.yellow('No build script found in package.json, skipping'));
  }
}

async function stagePreDeployVerification() {
  const stage = 'PRE-DEPLOY';
  log(stage, 'Running pre-deployment verification...');

  // Verify SBOM exists and is valid
  const sbomPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json');
  if (!fs.existsSync(sbomPath)) {
    throw new Error('SBOM not found. Cannot deploy without SBOM.');
  }

  // Verify SBOM integrity before deploy
  const sbomHashPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json.sha256');
  if (fs.existsSync(sbomHashPath)) {
    const currentHash = computeFileHash(sbomPath);
    const storedHashLine = fs.readFileSync(sbomHashPath, 'utf-8').trim();
    const storedHash = storedHashLine.split(/\s+/)[0];

    if (currentHash !== storedHash) {
      throw new Error('SBOM integrity check failed before deployment. SBOM may have been tampered with.');
    }
  }

  // Verify build manifest exists
  const manifestPath = path.join(CONFIG.artifactDir, 'build-manifest.json');
  if (fs.existsSync(manifestPath)) {
    const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
    log(stage, `Deploying: ${manifest.appName}@${manifest.appVersion}`);
    log(stage, `Build hash: ${manifest.buildHash}`);
  }

  // Verify audit report doesn't have critical issues
  const auditPath = path.join(CONFIG.artifactDir, 'audit-report.json');
  if (fs.existsSync(auditPath)) {
    try {
      const auditData = JSON.parse(fs.readFileSync(auditPath, 'utf-8'));
      if (auditData.metadata && auditData.metadata.vulnerabilities) {
        const critical = auditData.metadata.vulnerabilities.critical || 0;
        if (critical > 0) {
          throw new Error(`Cannot deploy: ${critical} critical vulnerabilities remain`);
        }
      }
    } catch (e) {
      if (e.message.includes('Cannot deploy')) throw e;
      log(stage, colors.yellow('Could not verify audit report'));
    }
  }

  logSuccess(stage, 'Pre-deployment verification passed');
}

async function stageDeploy() {
  const stage = 'DEPLOY';
  log(stage, `Deploying to ${CONFIG.deployTarget}...`);

  const deployToken = process.env.DEPLOY_TOKEN;
  if (!deployToken) {
    log(stage, colors.yellow('DEPLOY_TOKEN not set. Skipping actual deployment.'));
    log(stage, 'In production, set DEPLOY_TOKEN to enable deployment.');
    logSuccess(stage, 'Deploy stage completed (dry run)');
    return;
  }

  // Create deployment package
  const packageJson = JSON.parse(fs.readFileSync(path.resolve(__dirname, 'package.json'), 'utf-8'));
  const deploymentId = `${packageJson.name}-${packageJson.version}-${Date.now()}`;

  const deploymentRecord = {
    id: deploymentId,
    timestamp: new Date().toISOString(),
    target: CONFIG.deployTarget,
    version: packageJson.version,
    nodeVersion: process.version,
    sbomIncluded: true,
    sbomHash: computeFileHash(path.join(CONFIG.sbomDir, 'sbom.cdx.json')),
  };

  // Include build manifest hash
  const manifestPath = path.join(CONFIG.artifactDir, 'build-manifest.json');
  if (fs.existsSync(manifestPath)) {
    const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
    deploymentRecord.buildHash = manifest.buildHash;
  }

  // Sign deployment record
  const recordString = JSON.stringify(deploymentRecord);
  const recordHash = crypto.createHash('sha256').update(recordString).digest('hex');
  deploymentRecord.signature = recordHash;

  // Save deployment record
  const deployRecordPath = path.join(CONFIG.artifactDir, 'deployment-record.json');
  fs.writeFileSync(deployRecordPath, JSON.stringify(deploymentRecord, null, 2), { mode: 0o644 });

  // Execute deployment command (customize for your infrastructure)
  // Examples: rsync, docker push, aws s3 sync, kubectl apply, etc.
  const deployScript = path.resolve(__dirname, 'scripts', 'deploy.sh');
  if (fs.existsSync(deployScript)) {
    const deployResult = execCommand(`bash "${deployScript}" "${CONFIG.deployTarget}"`, {
      timeout: 600000,
      env: {
        ...process.env,
        DEPLOYMENT_ID: deploymentId,
        BUILD_DIR: CONFIG.buildDir,
        SBOM_DIR: CONFIG.sbomDir,
        ARTIFACT_DIR: CONFIG.artifactDir,
        // Don't pass DEPLOY_TOKEN via command line - it's already in env
      },
    });

    if (!deployResult.success) {
      throw new Error(`Deployment failed:\n${deployResult.error || deployResult.output}`);
    }
  } else {
    log(stage, colors.yellow('No deploy script found at scripts/deploy.sh'));
    log(stage, `Deployment record created: ${deploymentId}`);
  }

  logSuccess(stage, `Deployment ${deploymentId} completed`);
}

async function stagePostDeployVerification() {
  const stage = 'POST-DEPLOY';
  log(stage, 'Running post-deployment verification...');

  // Health check (customize URL for your application)
  const healthCheckUrl = process.env.HEALTH_CHECK_URL;
  if (healthCheckUrl) {
    let healthy = false;
    for (let attempt = 1; attempt <= CONFIG.maxRetries; attempt++) {
      log(stage, `Health check attempt ${attempt}/${CONFIG.maxRetries}...`);

      const curlResult = execCommand(
        `curl -sf -o /dev/null -w "%{http_code}" --max-time 10 "${healthCheckUrl}"`,
        { timeout: 15000 }
      );

      if (curlResult.success && curlResult.output === '200') {
        healthy = true;
        break;
      }

      if (attempt < CONFIG.maxRetries) {
        log(stage, `Health check failed, retrying in 5 seconds...`);
        await new Promise((resolve) => setTimeout(resolve, 5000));
      }
    }

    if (!healthy) {
      throw new Error('Post-deployment health check failed. Consider rolling back.');
    }
  } else {
    log(stage, colors.yellow('HEALTH_CHECK_URL not set, skipping health check'));
  }

  logSuccess(stage, 'Post-deployment verification passed');
}

function generatePipelineSummary(stageResults, startTime) {
  const totalDuration = ((Date.now() - startTime) / 1000).toFixed(2);

  console.log('\n' + colors.bold('═══════════════════════════════════════════════'));
  console.log(colors.bold('  CI/CD Pipeline Summary'));
  console.log(colors.bold('═══════════════════════════════════════════════'));

  for (const result of stageResults) {
    const status = result.success
      ? colors.green('✓ PASSED')
      : colors.red('✗ FAILED');
    const duration = `${result.duration.toFixed(2)}s`;
    console.log(`  ${status}  ${result.name.padEnd(25)} ${duration}`);
  }

  console.log(colors.bold('───────────────────────────────────────────────'));
  console.log(`  Total Duration: ${totalDuration}s`);

  const allPassed = stageResults.every((r) => r.success);
  if (allPassed) {
    console.log(colors.green(colors.bold('  Result: PIPELINE SUCCEEDED')));
  } else {
    const failedStage = stageResults.find((r) => !r.success);
    console.log(colors.red(colors.bold(`  Result: PIPELINE FAILED at ${failedStage.name}`)));
  }

  console.log(colors.bold('═══════════════════════════════════════════════\n'));

  return allPassed;
}

// ─── Main Pipeline Execution ─────────────────────────────────────────────────

async function runPipeline() {
  const pipelineStartTime = Date.now();
  const stageResults = [];

  const stages = [
    { name: 'Preflight Checks', fn: stagePreflightChecks },
    { name: 'Install Dependencies', fn: stageInstallDependencies },
    { name: 'Security Audit', fn: stageSecurityAudit },
    { name: 'Generate SBOM', fn: stageGenerateSBOM, captureResult: true },
    { name: 'Validate SBOM', fn: null }, // Special handling below
    { name: 'Lint', fn: stageLint },
    { name: 'Test', fn: stageTest },
    { name: 'Build', fn: stageBuild },
    { name: 'Pre-Deploy Verification', fn: stagePreDeployVerification },
    { name: 'Deploy', fn: stageDeploy },
    { name: 'Post-Deploy Verification', fn: stagePostDeployVerification },
  ];

  let sbomData = null;

  for (const stage of stages) {
    const stageStart = Date.now();

    try {
      if (stage.name === 'Validate SBOM') {
        if (sbomData) {
          validateSBOM(sbomData);
        } else {
          // Load from file if not captured
          const sbomPath = path.join(CONFIG.sbomDir, 'sbom.cdx.json');
          if (fs.existsSync(sbomPath)) {
            sbomData = JSON.parse(fs.readFileSync(sbomPath, 'utf-8'));
            validateSBOM(sbomData);
          } else {
            throw new Error('SBOM file not found for validation');
          }
        }
      } else {
        const result = await stage.fn();
        if (stage.captureResult && result) {
          sbomData = result;
        }
      }

      stageResults.push({
        name: stage.name,
        success: true,
        duration: (Date.now() - stageStart) / 1000,
      });
    } catch (error) {
      stageResults.push({
        name: stage.name,
        success: false,
        duration: (Date.now() - stageStart) / 1000,
        error: error.message,
      });

      logError(stage.name, error.message);

      // Stop pipeline on failure
      break;
    }
  }

  const success = generatePipelineSummary(stageResults, pipelineStartTime);

  // Write pipeline results as artifact
  const pipelineResultPath = path.join(CONFIG.artifactDir, 'pipeline-result.json');
  ensureDirectory(CONFIG.artifactDir);
  fs.writeFileSync(
    pipelineResultPath,
    JSON.stringify(
      {
        timestamp: new Date().toISOString(),
        success,
        stages: stageResults,
        totalDuration: (Date.now() - pipelineStartTime) / 1000,
      },
      null,
      2
    ),
    { mode: 0o644 }
  );

  process.exit(success ? 0 : 1);
}

// Handle uncaught errors
process.on('uncaughtException', (error) => {
  logError('PIPELINE', `Uncaught exception: ${error.message}`);
  process.exit(1);
});

process.on('unhandledRejection', (reason) => {
  logError('PIPELINE', `Unhandled rejection: ${reason}`);
  process.exit(1);
});

// Run
runPipeline();